sys_script.script:
(function executeRule(current, previous) {

var department = current.getValue('medical_department');

var doctorWorkload = {};
var doctorList = [];


// Find doctors in same department
var doctor = new GlideRecord('sys_user');
doctor.addQuery('title', 'Doctor');
doctor.addQuery('medical_department', department);
doctor.query();


while (doctor.next()) {

    doctorList.push(doctor.sys_id.toString());
    doctorWorkload[doctor.sys_id.toString()] = 0;

}


// Count patients per doctor
var patient = new GlideRecord('x_1954503_smartc_0_patient');
patient.addQuery('status', '!=', 'discharged');
patient.query();

while (patient.next()) {

    var assignedDoctor = patient.getValue('assigned_doctor');

    if (doctorWorkload[assignedDoctor] != undefined) {

        doctorWorkload[assignedDoctor]++;

    }

}


// Find doctor with least patients
var selectedDoctor = null;
var lowestLoad = 999;

for (var i = 0; i < doctorList.length; i++) {

    var doc = doctorList[i];

    if (doctorWorkload[doc] < lowestLoad) {

        lowestLoad = doctorWorkload[doc];
        selectedDoctor = doc;

    }

}


// Assign doctor
if (selectedDoctor) {

    current.setValue('assigned_doctor', selectedDoctor);

}

})(current, previous);
